import { useState, useEffect } from "react";
import axios from "axios";
import { useParams } from "react-router-dom";

const API = "https://team-task-manager-4-7vl7.onrender.com";

export default function Tasks() {
  const { projectId } = useParams(); // ✅ get project id from URL

  const [tasks, setTasks] = useState([]);
  const [form, setForm] = useState({
    title: "",
    description: "",
    dueDate: "",
    priority: "Medium"
  });

  // 🔄 Load tasks when page opens
  useEffect(() => {
    if (projectId) {
      loadTasks();
    }
  }, [projectId]);

  // 📥 GET TASKS
  const loadTasks = async () => {
    try {
      console.log("PROJECT ID:", projectId);

      const res = await axios.get(`${API}/api/tasks/${projectId}`);
      setTasks(res.data);

    } catch (err) {
      console.error("GET TASK ERROR:", err);
    }
  };

  // ➕ CREATE TASK
  const createTask = async (e) => {
    e.preventDefault();

    try {
      await axios.post(`${API}/api/tasks`, {
        title: form.title,
        description: form.description,
        dueDate: form.dueDate,
        priority: form.priority,
        project: projectId
      });

      // clear form
      setForm({
        title: "",
        description: "",
        dueDate: "",
        priority: "Medium"
      });

      loadTasks(); // refresh list

    } catch (err) {
      console.error("CREATE ERROR:", err);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Project Tasks</h2>

      {/* 🧾 FORM */}
      <form onSubmit={createTask} style={{ marginBottom: 20 }}>
        
        <input
          placeholder="Title"
          value={form.title}
          onChange={(e) =>
            setForm({ ...form, title: e.target.value })
          }
          required
          style={{ display: "block", marginBottom: 10 }}
        />

        <input
          placeholder="Description"
          value={form.description}
          onChange={(e) =>
            setForm({ ...form, description: e.target.value })
          }
          style={{ display: "block", marginBottom: 10 }}
        />

        <input
          type="date"
          value={form.dueDate}
          onChange={(e) =>
            setForm({ ...form, dueDate: e.target.value })
          }
          style={{ display: "block", marginBottom: 10 }}
        />

        <select
          value={form.priority}
          onChange={(e) =>
            setForm({ ...form, priority: e.target.value })
          }
          style={{ display: "block", marginBottom: 10 }}
        >
          <option>Low</option>
          <option>Medium</option>
          <option>High</option>
        </select>

        <button type="submit">Create Task</button>
      </form>

      <hr />

      {/* 📦 TASK LIST */}
      {tasks.length === 0 ? (
        <p>No tasks yet</p>
      ) : (
        tasks.map((t) => (
          <div key={t._id} style={{ marginBottom: 10 }}>
            <h4>{t.title}</h4>
            <p>{t.description}</p>
            <p>Status: {t.status}</p>
            <p>Priority: {t.priority}</p>
          </div>
        ))
      )}
    </div>
  );
}
